module RefModule(
    input wire [10:0] bin,
    output reg [3:0] ones,
    output reg [3:0] tens,
    output reg [3:0] hundreds,
    output reg [3:0] thousands
);parameter THOU = 1000;
parameter HUND = 100;
parameter TENS = 10;
parameter ONES = 1;

reg [10:0] unused_buffer;
integer i;
integer sub;

always @ (*)
begin
	unused_buffer = bin;
	ones = 4'd0;
    tens = 4'd0;
    hundreds = 4'd0;
    thousands = 4'd0;
    sub = 0;
     if(unused_buffer >= THOU) begin
     	for(i = 0; i < 10; i = i + 1) begin
     		if(i*THOU < unused_buffer) begin
     			sub = sub + 1;
     		end
     	end
 		if(unused_buffer < sub*THOU) begin
 			sub = sub - 1;
 		end
     	unused_buffer = unused_buffer - sub*THOU;
     	thousands = sub;
     end
     sub = 0;
     if(unused_buffer >= HUND) begin
     	for(i = 0; i < 10; i = i + 1) begin
     		if(i*HUND < unused_buffer) begin
     			sub = sub + 1;
     		end
     	end
 		if(unused_buffer < sub*HUND) begin
 			sub = sub - 1;
 		end
     	unused_buffer = unused_buffer - sub*HUND;
     	hundreds = sub;
     end
     sub = 0;
     if(unused_buffer >= TENS) begin
     	for(i = 0; i < 10; i = i + 1) begin
     		if(i*TENS < unused_buffer) begin
     			sub = sub + 1;
     		end
     	end
 		if(unused_buffer < sub*TENS) begin
 			sub = sub - 1;
 		end
     	unused_buffer = unused_buffer - sub*TENS;
     	tens = sub;
     end
     sub = 0;
     if(unused_buffer >= ONES) begin
     	for(i = 0; i < 10; i = i + 1) begin
     		if(i*ONES < unused_buffer) begin
     			sub = sub + 1;
     		end
     	end
 		if(unused_buffer < sub) begin
 			sub = sub - 1;
 		end
     	unused_buffer = unused_buffer - sub;
     	ones = sub;
     end
end

endmodule
